<?php require_once '../config/database.php'; require_once '../config/helpers.php'; if(empty($_SESSION['admin'])){header('Location: login.php');exit;} $orders=$pdo->query('SELECT * FROM orders ORDER BY id DESC LIMIT 20')->fetchAll(); $products=$pdo->query('SELECT * FROM products ORDER BY id DESC')->fetchAll(); ?>
<!doctype html><html lang="vi"><head><meta charset="utf-8"><link rel="stylesheet" href="../assets/css/style.css"><title>Admin</title></head><body><div class="admin-nav"><b>SUDES Admin</b><a href="logout.php">Đăng xuất</a></div><main class="admin-container"><h1>Quản trị website</h1><p><a class="btn" href="product_form.php">Thêm sản phẩm</a></p><h2>Sản phẩm</h2><table><tr><th>ID</th><th>Tên</th><th>Giá</th><th>Tồn kho</th><th></th></tr><?php foreach($products as $p): ?><tr><td><?=$p['id']?></td><td><?=$p['name']?></td><td><?=money(product_price($p))?></td><td><?=$p['stock']?></td><td><a href="product_form.php?id=<?=$p['id']?>">Sửa</a></td></tr><?php endforeach; ?></table><h2>Đơn hàng mới</h2><table><tr><th>Mã</th><th>Khách</th><th>SĐT</th><th>Tổng</th><th>Ngày</th></tr><?php foreach($orders as $o): ?><tr><td>#<?=$o['id']?></td><td><?=$o['customer_name']?></td><td><?=$o['phone']?></td><td><?=money($o['total'])?></td><td><?=$o['created_at']?></td></tr><?php endforeach; ?></table></main></body></html>
